 1	{"id":"minitron-2407.14679","title":"Compact Language Models via Pruning and Knowledge Distillation (Minitron)","venue":"arXiv (NVIDIA)","year":2024,"url":"https://arxiv.org/abs/2407.14679","claim":"Depth+width+head+MLP pruning with KD-based retraining on <3% of original data; 8B/4B derived from 15B need up to 40x fewer training tokens per model than from-scratch; 1.8x compute saving for the family; up to 16% MMLU improvement over from-scratch training at equal token budget; Minitron comparable to Mistral-7B/Gemma-7B/Llama-3-8B","verified":true}
 2	{"id":"minitron-practice-2408.11796","title":"LLM Pruning and Distillation in Practice: The Minitron Approach","venue":"arXiv (NVIDIA)","year":2024,"url":"https://arxiv.org/abs/2408.11796","claim":"Practice recipe: teacher correction (lightly fine-tune teacher on the distillation dataset when original pretraining data unavailable) before KD; evaluates depth pruning vs joint hidden/attention/MLP width pruning; Llama-3.1-8B->4B and Mistral-NeMo-12B->Minitron-8B (state-of-the-art at release), weights open","verified":true}
 3	{"id":"sheared-llama-2310.06694","title":"Sheared LLaMA: Accelerating Language Model Pre-training via Structured Pruning","venue":"ICLR 2024 (openreview.net/forum?id=09iOdaeOzp)","year":2024,"url":"https://arxiv.org/abs/2310.06694","claim":"Targeted structured pruning (layers/heads/intermediate/hidden to a target shape, end-to-end) + dynamic batch loading (domain-loss-driven data re-mixing); LLaMA2-7B pruned to 1.3B/2.7B beats Pythia/INCITE/OpenLLaMA/concurrent TinyLlama at equivalent sizes using ~3% of from-scratch compute — accounting caveat: the 3% excludes the donor's pretraining compute","verified":true}
 4	{"id":"llm-pruner-2305.11627","title":"LLM-Pruner: On the Structural Pruning of Large Language Models","venue":"NeurIPS 2023","year":2023,"url":"https://arxiv.org/abs/2305.11627","claim":"Gradient-based structural pruning over dependency-coupled groups, task-agnostic; recovery via LoRA in ~3h on 50k samples; at 20% pruning ratio LLaMA/Vicuna/ChatGLM retain 'satisfactory' zero-shot classification/generation","verified":true}
 5	{"id":"slicegpt-2401.15024","title":"SliceGPT: Compress Large Language Models by Deleting Rows and Columns","venue":"ICLR 2024","year":2024,"url":"https://arxiv.org/abs/2401.15024","claim":"Computational-invariance-based structured compression: orthogonal transform of the residual stream absorbed into adjacent weight matrices, then PCA-ranked rows/columns deleted (embedding dimension reduced); 25% slicing keeps 99% zero-shot performance on LLAMA2-70B and OPT-66B but only 90% on Phi-2 (2.7B) — smaller models degrade more; inference cost down to 64-66% of dense","verified":true}
 6	{"id":"deeper-layers-2403.17887","title":"The Unreasonable Ineffectiveness of the Deeper Layers","venue":"ICLR 2025","year":2025,"url":"https://arxiv.org/abs/2403.17887","claim":"Layer pruning selected by inter-layer representational (angular) similarity + QLoRA healing: minimal QA-benchmark degradation until up to ~half the layers of some open-weight models are removed; interpreted as under-utilisation of deep layers or shallow-layer-dominant knowledge storage","verified":true}
 7	{"id":"mobilellm-2402.14905","title":"MobileLLM: Optimizing Sub-billion Parameter Language Models for On-Device Use Cases","venue":"ICML 2024","year":2024,"url":"https://arxiv.org/abs/2402.14905","claim":"At 125M/350M architecture dominates: deep-and-thin, embedding sharing, grouped-query attention, block-wise weight sharing; +2.7pp/+4.3pp over prior 125M/350M SOTA; API-calling correctness close to LLaMA-v2-7B","verified":true}
 8	{"id":"distill-scaling-2502.08606","title":"Distillation Scaling Laws","venue":"ICML 2025 (Apple/Oxford)","year":2025,"url":"https://arxiv.org/abs/2502.08606","claim":"Distillation scaling law predicting student performance from compute split across teacher/student; distillation beats supervised pretraining only up to a compute level that scales predictably with student size and only when a teacher exists or many students amortise it; capacity gap (stronger teacher -> worse student) explained as learning-capacity gap; compute-optimal recipes given","verified":true}
 9	{"id":"quarot-2404.00456","title":"QuaRot: Outlier-Free 4-Bit Inference in Rotated LLMs","venue":"arXiv 2024 (NeurIPS 2024 per community records - venue not confirmed at source)","year":2024,"url":"https://arxiv.org/abs/2404.00456","claim":"Per-component invariance accounting (HTML v2 fetched): RMSNorm(X)=RMSNorm(XQ^T)Q lets residual-stream rotations be absorbed into W_q/W_k/W_v/W_up/W_gate (as Q^T diag(alpha) W after pre-fusing RMSNorm gains) and W_down/W_out (as H W Q); online Hadamard REQUIRED before FFN down-projection (gating nonlinearity regenerates outliers) and head-wise on keys/values (RoPE sits between projection and use: 'the existence of Pos prevents us from directly fusing the Hadamard matrix into W_q and W_k'); 4-bit LLaMA2-70B: <=0.47 WikiText-2 ppl loss, 99% zero-shot retained","verified":true}
10	{"id":"spinquant-2405.16406","title":"SpinQuant: LLM Quantization with Learned Rotations","venue":"ICLR 2025","year":2025,"url":"https://arxiv.org/abs/2405.16406","claim":"Identifies rotation parameterisations that leave full-precision output invariant; learns rotations (Stiefel-manifold optimisation) instead of random ones — random rotation choice alone swings downstream zero-shot reasoning by up to 13 points at 4-bit; strong W4A4KV4 results incl. LLaMA-3-8B. R1-R4 taxonomy (which merge into weights vs run online) NOT verified at source this session (HTML fetch 404) — carried from abstract only","verified":true}
11	{"id":"signed-perm-2606.31963","title":"Signed-Permutation Coordinate Transport for RMSNorm Transformers","venue":"arXiv","year":2026,"url":"https://arxiv.org/html/2606.31963","claim":"With generic per-channel RMSNorm gain the exact gauge (symmetry) group of the coordinate system is the signed-permutation group B_d = S_d x {+-1}^d, NOT O(d); LayerNorm charts have only permutation gauge S_d; permutation-only alignment is symmetry-incomplete for RMSNorm models (worked example: SAE reconstruction NMSE 0.004 -> 1.08 under permutation-only vs signed-permutation transport); steering vectors, SAEs, top-k neuron sets, attribution lists must be co-transported","verified":true}
12	{"id":"lmc-billion-2606.23607","title":"Scaling Linear Mode Connectivity and Merging to Billion Parameter Pretrained Transformers","venue":"arXiv","year":2026,"url":"https://arxiv.org/abs/2606.23607","claim":"Functionality-preserving weight transformations, jointly learned per model pair, align independently trained transformers onto a near-zero-loss-barrier linear interpolation path at billion-parameter scale (WikiText LMs; ViT-L >=69% ImageNet along path). The stronger 'rotation hypothesis' framing (same function up to a residual-stream rotation learnable from one batch) seen only in search snippets - UNVERIFIED at source","verified":true}
13	{"id":"lrh-2311.03658","title":"The Linear Representation Hypothesis and the Geometry of Large Language Models","venue":"ICML 2024 (also NeurIPS 2023 CRL workshop)","year":2024,"url":"https://arxiv.org/abs/2311.03658","claim":"Formalises linear representation of concepts; Euclidean inner product is the wrong geometry for concept directions — a 'causal inner product' (whitened basis) makes causally separable concepts orthogonal; validated on LLaMA-2; implies concept directions are generically NON-orthogonal in the naive residual-stream basis","verified":true}
14	{"id":"superposition-2209.10652","title":"Toy Models of Superposition","venue":"arXiv / transformer-circuits (Anthropic)","year":2022,"url":"https://arxiv.org/abs/2209.10652","claim":"Networks store more sparse features than dimensions as NON-orthogonal directions (superposition); phase transition governs when features enter superposition; polysemanticity is a strategic compression, not a failure — foundational reason no clean per-dimension concept ownership exists","verified":true}
15	{"id":"sae-canonical-2502.04878","title":"Sparse Autoencoders Do Not Find Canonical Units of Analysis","venue":"ICLR 2025 (per arXiv page)","year":2025,"url":"https://arxiv.org/abs/2502.04878","claim":"SAE stitching shows smaller SAEs are incomplete (larger SAEs contain novel latents, not just refinements); meta-SAEs decompose latents into interpretable parts ('Einstein' -> 'scientist'+'Germany'+'famous person'); conclusion: no canonical atomic feature set at any SAE size","verified":true}
16	{"id":"sae-seeds-2501.16615","title":"Sparse Autoencoders Trained on the Same Data Learn Different Features","venue":"arXiv (EleutherAI)","year":2025,"url":"https://arxiv.org/abs/2501.16615","claim":"131K-latent SAE on Llama-3-8B: only ~30% of features shared across random seeds; TopK SAEs more seed-dependent than ReLU+L1; consistent across layers/datasets/architectures — SAE decompositions are pragmatic, not unique","verified":true}
17	{"id":"absorption-2409.14507","title":"A is for Absorption: Studying Feature Splitting and Absorption in Sparse Autoencoders","venue":"NeurIPS 2025 (oral, per arXiv page)","year":2025,"url":"https://arxiv.org/abs/2409.14507","claim":"Feature absorption: parent features stop firing where children absorb them (hierarchy fragmentation); validated across hundreds of LLM SAEs; not fixable by size/sparsity tuning; SAE latents unreliable as COMPLETE concept indicators — fatal for 'this latent = this concept everywhere' assumptions","verified":true}
18	{"id":"sae-probing-2502.16681","title":"Are Sparse Autoencoders Useful? A Case Study in Sparse Probing","venue":"arXiv","year":2025,"url":"https://arxiv.org/abs/2502.16681","claim":"Across data-scarce, class-imbalanced, label-noise, and distribution-shift probing regimes, SAE probes occasionally beat baselines on individual datasets but no SAE(+ensemble) method consistently beats standard baselines","verified":true}
19	{"id":"sparse-feature-circuits-2403.19647","title":"Sparse Feature Circuits: Discovering and Editing Interpretable Causal Graphs in Language Models","venue":"ICLR 2025","year":2025,"url":"https://arxiv.org/abs/2403.19647","claim":"Attribution-based discovery of causal circuits of SAE features (Gemma/Pythia); SHIFT: ablating human-judged task-irrelevant features improves classifier generalisation — the published template for interp-guided causal ablation-with-purpose (closest methodological ancestor of P3-E-DD-0 steps 1-2)","verified":true}
20	{"id":"gdm-sae-negative-2025","title":"Negative Results for SAEs On Downstream Tasks and Deprioritising SAE Research (GDM mech-interp team)","venue":"Alignment Forum (Google DeepMind team post)","year":2025,"url":"https://www.alignmentforum.org/posts/4uXCAJNuPKtKBsi28/sae-progress-update-negative-results-for-saes-on-downstream","claim":"2025-03-26: dense linear probes vastly outperform SAE probes incl. OOD harmful-intent detection; chat-data SAE finetuning closes only ~half the gap; GDM deprioritises fundamental SAE research (not 'SAEs are useless'); SAEs still useful for dataset debugging/spurious-correlation discovery","verified":true}
21	{"id":"pruning-reshapes-2603.25325","title":"How Pruning Reshapes Features: Sparse Autoencoder Analysis of Weight-Pruned Language Models","venue":"arXiv","year":2026,"url":"https://arxiv.org/abs/2603.25325","claim":"3 model families x 2 pruning strategies x 6 sparsity levels: RARE (low-firing) SAE features survive pruning better than frequent ones (Spearman rho=-1.0 in 11/17 conditions); Wanda preserves feature geometry up to 3.7x better than magnitude pruning; pretrained SAEs transfer to Wanda-pruned models to 50% sparsity; geometric preservation does NOT predict causal importance","verified":true}
22	{"id":"pythia-2304.01373","title":"Pythia: A Suite for Analyzing Large Language Models Across Training and Scaling","venue":"ICML 2023","year":2023,"url":"https://arxiv.org/abs/2304.01373","claim":"16 models 70M-12B, identical public data in identical order, 154 checkpoints each + exact dataloader reconstruction — the controlled substrate for size-vs-capability curves and the second H-DD donor (Pythia-160M; LayerNorm, parallel blocks)","verified":true}
23	{"id":"smollm2-2502.02737","title":"SmolLM2: When Smol Goes Big — Data-Centric Training of a Small Language Model","venue":"arXiv (HuggingFace); COLM 2025 status not confirmed at source","year":2025,"url":"https://arxiv.org/abs/2502.02737","claim":"1.7B trained ~11T tokens, multi-stage data-centric mixing (FineMath/Stack-Edu/SmolTalk introduced); outperforms Qwen2.5-1.5B and Llama-3.2-1B; 135M/360M siblings — the R-1/R-2 donor anchors and the size-vs-capability practice frontier at 100M-2B","verified":true}
24	{"id":"capacity-2404.05405","title":"Physics of Language Models Part 3.3: Knowledge Capacity Scaling Laws","venue":"arXiv (Meta/MBZUAI); ICML 2025 status not confirmed at source","year":2024,"url":"https://arxiv.org/abs/2404.05405","claim":"LMs store max ~2 bits of factual knowledge per parameter (bit-complexity of stored tuples, controlled synthetic corpora), stable to int8 quantisation; GPT-2-with-RoPE matches/exceeds LLaMA/Mistral architectures at knowledge storage; MoE sparsity, insufficient exposure, and junk data reduce capacity; domain-name prepending increases it","verified":true}
25	{"id":"lmlm-2505.15962","title":"Pre-training Limited Memory Language Models with Internal and External Knowledge (LMLM)","venue":"arXiv","year":2025,"url":"https://arxiv.org/abs/2505.15962","claim":"Pretraining corpus annotated with database lookups; retrieved factual spans MASKED FROM THE LOSS so the model learns targeted lookup instead of memorisation; small LMLMs competitive with substantially larger vanilla LLMs on standard benchmarks; facts editable/verifiable in the external DB. Closest H-DD prior art on the destination architecture — but train-time externalisation of a NEW model, NOT post-hoc identified-parameter removal from an existing donor","verified":true}
26	{"id":"memory-layers-2412.09764","title":"Memory Layers at Scale","venue":"arXiv (Meta)","year":2024,"url":"https://arxiv.org/abs/2412.09764","claim":"Trainable sparse key-value memory layers replacing FFN capacity: beat dense models given >2x the compute and MoE at matched resources, largest gains on factual tasks; scaled to 128B memory parameters over 1T training tokens — factual capacity is separable from dense compute and relocatable into a lookup structure","verified":true}
27	{"id":"hase-localization-2301.04213","title":"Does Localization Inform Editing? Surprising Differences in Causality-Based Localization vs. Knowledge Editing","venue":"NeurIPS 2023 (spotlight)","year":2023,"url":"https://arxiv.org/abs/2301.04213","claim":"Causal-tracing localisation provides NO insight into which MLP layer is best to edit; editing success is essentially unrelated to where tracing places the fact — the standing threat to any 'semantically-identified parameters' program and the reason P3-E-DD-0 requires ablate/patch + restoration evidence, not localisation alone","verified":true}
28	{"id":"retro-2112.04426","title":"Improving Language Models by Retrieving from Trillions of Tokens (RETRO)","venue":"arXiv 2021/2022 (DeepMind; ICML 2022 status not confirmed at source)","year":2022,"url":"https://arxiv.org/abs/2112.04426","claim":"7.5B RETRO with 2T-token retrieval DB (frozen BERT retriever + chunked cross-attention) matches GPT-3/Jurassic-1 on the Pile with 25x fewer parameters; RETROfit: a pretrained transformer can be rapidly retrofitted with retrieval — retrieval substitutes for parametric capacity at equal quality","verified":true}
29	{"id":"memorize-retrieve-2604.00715","title":"To Memorize or to Retrieve: Scaling Laws for RAG-Considerate Pretraining","venue":"arXiv","year":2026,"url":"https://arxiv.org/abs/2604.00715","claim":"30M-3B models, varied pretraining tokens x retrieval-store size under fixed data budgets: retrieval improves all scales; 3-D scaling framework (params x tokens x retrieval corpus); optimal parametric-vs-retrieval allocation is task- and saturation-dependent, not universal","verified":true}
30	{"id":"sspu-2505.24428","title":"Model Unlearning via Sparse Autoencoder Subspace Guided Projections (SSPU)","venue":"arXiv","year":2025,"url":"https://arxiv.org/abs/2505.24428","claim":"SAE-guided layer/feature selection + QR subspace construction + constrained optimisation steering activations into an 'irrelevant' subspace; -3.22% harmful-knowledge accuracy vs strongest baseline on WMDP-Cyber with utility retained; REMOVAL ONLY — no external-store backfill, no parameter deletion","verified":true}
31	{"id":"superweight-2411.07191","title":"The Super Weight in Large Language Models","venue":"arXiv (Apple/Notre Dame)","year":2024,"url":"https://arxiv.org/abs/2411.07191","claim":"Pruning as few as ONE scalar parameter can destroy generation (perplexity up 3 orders of magnitude); identified data-free in a single forward pass; induce rare massive 'super activations' — surgery-fragility floor: any H-DD arm must protect identified super weights or explain their handling","verified":true}
32	{"id":"kb-atlas-2208.03299","title":"Atlas: Few-shot Learning with Retrieval Augmented Language Models","venue":"JMLR 2023 (KB record kb/records/arxiv_2208.03299.json - NOT re-verified at source this session)","year":2023,"url":"https://arxiv.org/abs/2208.03299","claim":"11B retrieval-augmented model beats 540B PaLM on NaturalQuestions-64-shot (KB-recorded claim); joint retriever-reader training — second retrieval-substitutes-for-parameters datapoint","verified":false}
33	{"id":"kb-llama-slayer-2410.02330","title":"Llama SLayer 8B: Shallow Layers Hold the Key to Knowledge Injection","venue":"EMNLP 2024 findings (KB record kb/records/arxiv_2410.02330.json - NOT re-verified at source this session)","year":2024,"url":"https://arxiv.org/abs/2410.02330","claim":"Layer-importance ranking for knowledge injection: shallow layers critical, deeper layers prunable for injection purposes (KB-recorded claim) — consistent with deeper-layers result","verified":false}
34	{"id":"kb-quasi-orth-2503.24277","title":"Evaluating and Designing Sparse Autoencoders by Approximating Quasi-Orthogonality","venue":"arXiv (KB record kb/records/arxiv_2503.24277.json - NOT re-verified at source this session)","year":2025,"url":"https://arxiv.org/abs/2503.24277","claim":"SAE dictionaries are at best QUASI-orthogonal; norm-matching/adaptive-sparsity designs built on approximate orthogonality, confirming exact-orthogonal-block assumptions are unfounded (KB-recorded claim)","verified":false}
35	{"id":"lmlm-scale-detail","title":"LMLM result magnitudes (which sizes match which larger models)","venue":"arXiv HTML (not extracted this session)","year":2025,"url":"https://arxiv.org/html/2505.15962v2","claim":"Exact size-vs-match numbers for LMLM (e.g. which parameter count matches which vanilla size on TriviaQA/hallucination metrics) not extracted from abstract — UNVERIFIED pending full-text read in P3-D-DD","verified":false}
